"use client";

import { useState, useCallback, useRef } from "react";

import type { UploadQueueItem } from "@/types/video";
import { extractVideoMetadata } from "@/lib/video/metadata";
import { completeUploadAction } from "@/actions/uploads/complete-upload";

/* ============================================
   useUploadQueue — Client-side upload manager
   Handles file queue, upload to R2, progress,
   cancel, retry, and completion.
   ============================================ */

export function useUploadQueue(projectId: string | null) {
  const [items, setItems] = useState<UploadQueueItem[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const abortControllers = useRef<Map<string, AbortController>>(new Map());

  const addFiles = useCallback((files: FileList | File[]) => {
    const list = Array.from(files);
    const newItems: UploadQueueItem[] = list.map((file) => ({
      id: crypto.randomUUID(),
      file,
      status: "waiting" as const,
      progress: 0,
    }));
    setItems((prev) => [...prev, ...newItems]);
  }, []);

  const removeItem = useCallback((id: string) => {
    const controller = abortControllers.current.get(id);
    if (controller) {
      controller.abort();
      abortControllers.current.delete(id);
    }
    setItems((prev) => prev.filter((f) => f.id !== id));
  }, []);

  const updateItem = useCallback(
    (id: string, updates: Partial<UploadQueueItem>) => {
      setItems((prev) =>
        prev.map((f) => (f.id === id ? { ...f, ...updates } : f))
      );
    },
    []
  );

  const clearCompleted = useCallback(() => {
    setItems((prev) => prev.filter((f) => f.status !== "completed"));
  }, []);

  const clearAll = useCallback(() => {
    abortControllers.current.forEach((c) => c.abort());
    abortControllers.current.clear();
    setItems([]);
  }, []);

  const uploadFile = useCallback(
    async (item: UploadQueueItem) => {
      if (!projectId) return;

      const abortController = new AbortController();
      abortControllers.current.set(item.id, abortController);

      updateItem(item.id, { status: "uploading", progress: 0, error: undefined });

      try {
        // Extract metadata client-side
        let duration: number | undefined;
        let width: number | undefined;
        let height: number | undefined;
        try {
          const meta = await extractVideoMetadata(item.file);
          duration = meta.duration || undefined;
          width = meta.width || undefined;
          height = meta.height || undefined;
        } catch {
          // Metadata extraction failed — continue without it
        }

        // Upload via FormData to /api/upload
        const formData = new FormData();
        formData.append("file", item.file);
        formData.append("projectId", projectId);

        updateItem(item.id, { status: "uploading", progress: 10 });

        const response = await fetch("/api/upload", {
          method: "POST",
          body: formData,
          signal: abortController.signal,
        });

        if (!response.ok) {
          const data = await response.json().catch(() => ({}));
          throw new Error(data.error ?? "فشل في رفع الملف");
        }

        updateItem(item.id, { status: "processing", progress: 90 });

        const result = await response.json();

        // Complete upload — create video record
        const completeResult = await completeUploadAction({
          projectId,
          title: item.file.name.replace(/\.[^.]+$/, ""),
          originalFileName: item.file.name,
          storageKey: result.storageKey,
          storageBucket: result.storageBucket,
          mimeType: result.mimeType,
          extension: result.extension,
          fileSize: result.fileSize,
          duration,
          width,
          height,
        });

        if (completeResult.success) {
          updateItem(item.id, {
            status: "completed",
            progress: 100,
            videoId: completeResult.videoId,
          });
        } else {
          throw new Error(completeResult.error ?? "فشل في إكمال الرفع");
        }
      } catch (error) {
        if ((error as Error).name === "AbortError") {
          updateItem(item.id, { status: "failed", error: "تم الإلغاء" });
        } else {
          updateItem(item.id, {
            status: "failed",
            error: (error as Error).message ?? "فشل في الرفع",
          });
        }
      } finally {
        abortControllers.current.delete(item.id);
      }
    },
    [projectId, updateItem]
  );

  const startUpload = useCallback(async () => {
    if (!projectId || isUploading) return;
    setIsUploading(true);

    const pending = items.filter((f) => f.status === "waiting" || f.status === "failed");
    for (const item of pending) {
      await uploadFile(item);
    }

    setIsUploading(false);
  }, [projectId, isUploading, items, uploadFile]);

  const retryItem = useCallback(
    async (id: string) => {
      const item = items.find((f) => f.id === id);
      if (!item) return;
      updateItem(id, { status: "waiting", progress: 0, error: undefined });
      await uploadFile({ ...item, status: "waiting", progress: 0, error: undefined });
    },
    [items, updateItem, uploadFile]
  );

  const cancelUpload = useCallback((id: string) => {
    const controller = abortControllers.current.get(id);
    if (controller) {
      controller.abort();
      abortControllers.current.delete(id);
    }
    updateItem(id, { status: "failed", error: "تم الإلغاء" });
  }, [updateItem]);

  return {
    items,
    isUploading,
    addFiles,
    removeItem,
    retryItem,
    cancelUpload,
    startUpload,
    clearCompleted,
    clearAll,
  };
}

import { NextRequest, NextResponse } from "next/server";

import { getCurrentUser } from "@/lib/auth/session";
import { storageService } from "@/lib/storage/storage.service";
import { generateStorageKey, getMimeType, getExtension, validateVideoFile } from "@/lib/video/metadata";

export const maxDuration = 60;

/* ============================================
   Upload API Route
   Handles multipart video uploads via StorageService.
   Provider-agnostic — no direct Cloudflare imports.
   ============================================ */

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json(
      { error: "يجب تسجيل الدخول" },
      { status: 401 }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file") as File | null;
    const projectId = formData.get("projectId") as string | null;

    if (!file) {
      return NextResponse.json(
        { error: "الملف مطلوب" },
        { status: 400 }
      );
    }

    if (!projectId) {
      return NextResponse.json(
        { error: "المشروع مطلوب" },
        { status: 400 }
      );
    }

    // Validate file type and size
    const validation = validateVideoFile(file);
    if (!validation.valid) {
      return NextResponse.json(
        { error: validation.error },
        { status: 400 }
      );
    }

    // Generate storage key
    const storageKey = generateStorageKey(projectId, file.name);
    const mimeType = getMimeType(file);
    const extension = getExtension(file.name);

    // Read file as buffer
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // Upload via StorageService
    await storageService.upload({
      key: storageKey,
      body: buffer,
      contentType: mimeType,
      metadata: {
        "original-filename": file.name,
        "project-id": projectId,
      },
    });

    return NextResponse.json({
      success: true,
      storageKey,
      storageBucket: storageService.bucket,
      mimeType,
      extension,
      fileSize: file.size,
    });
  } catch (error) {
    console.error("Upload error:", error);
    return NextResponse.json(
      { error: "فشل في رفع الملف" },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useCallback, useRef } from "react";
import { UploadCloud, FolderOpen, Loader2, Trash2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { UploadProgressItem } from "@/components/uploads/upload-progress";
import { useUploadQueue } from "@/hooks/use-upload";
import { validateVideoFile } from "@/lib/video/metadata";
import { getProjectsAction } from "@/actions/projects/get-projects";
import { useEffect } from "react";

/* ============================================
   UploadZone — Drag & drop + click upload
   Requires project selection.
   ============================================ */

type ProjectOption = {
  id: string;
  name: string;
  projectCode: string;
};

export function UploadZone() {
  const [isDragging, setIsDragging] = useState(false);
  const [projectId, setProjectId] = useState<string | null>(null);
  const [projects, setProjects] = useState<ProjectOption[]>([]);
  const [loadingProjects, setLoadingProjects] = useState(true);
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({});
  const fileInputRef = useRef<HTMLInputElement>(null);
  const hasFetched = useRef(false);

  const {
    items,
    isUploading,
    addFiles,
    removeItem,
    retryItem,
    cancelUpload,
    startUpload,
    clearCompleted,
    clearAll,
  } = useUploadQueue(projectId);

  // Fetch projects for dropdown
  useEffect(() => {
    if (hasFetched.current) return;
    hasFetched.current = true;
    let active = true;
    (async () => {
      const result = await getProjectsAction({ page: 1, pageSize: 100 });
      if (!active) return;
      setProjects(
        result.items.map((p) => ({
          id: p.id,
          name: p.name,
          projectCode: p.projectCode,
        }))
      );
      setLoadingProjects(false);
    })();
    return () => { active = false };
  }, []);

  const handleFiles = useCallback(
    (fileList: FileList | File[]) => {
      const files = Array.from(fileList);
      const valid: File[] = [];
      const errors: Record<string, string> = {};

      for (const file of files) {
        const validation = validateVideoFile(file);
        if (!validation.valid) {
          errors[file.name] = validation.error ?? "ملف غير صالح";
        } else {
          valid.push(file);
        }
      }

      setValidationErrors(errors);
      if (valid.length > 0) {
        addFiles(valid);
      }
    },
    [addFiles]
  );

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);
      if (!projectId) return;
      handleFiles(e.dataTransfer.files);
    },
    [projectId, handleFiles]
  );

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleFileSelect = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) {
        handleFiles(e.target.files);
        e.target.value = "";
      }
    },
    [handleFiles]
  );

  const hasItems = items.length > 0;
  const hasPending = items.some(
    (f) => f.status === "waiting" || f.status === "failed"
  );

  return (
    <div className="space-y-4">
      {/* Project Selector */}
      <div className="space-y-1.5">
        <Label htmlFor="projectId">
          المشروع <span className="text-destructive">*</span>
        </Label>
        <select
          id="projectId"
          className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
          value={projectId ?? ""}
          onChange={(e) => setProjectId(e.target.value || null)}
          disabled={loadingProjects}
        >
          <option value="">
            {loadingProjects ? "جاري التحميل..." : "اختر المشروع"}
          </option>
          {projects.map((p) => (
            <option key={p.id} value={p.id}>
              {p.name} ({p.projectCode})
            </option>
          ))}
        </select>
      </div>

      {/* Drop Zone */}
      <div
        onDrop={handleDrop}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onClick={() => projectId && fileInputRef.current?.click()}
        role="button"
        tabIndex={0}
        aria-label="منطقة رفع الملفات"
        onKeyDown={(e) => {
          if (e.key === "Enter" && projectId) fileInputRef.current?.click();
        }}
        className={`flex cursor-pointer flex-col items-center justify-center gap-3 rounded-xl border-2 border-dashed p-8 transition-colors ${
          isDragging
            ? "border-primary bg-primary/5"
            : "border-muted-foreground/25 hover:border-muted-foreground/50"
        } ${!projectId ? "cursor-not-allowed opacity-50" : ""}`}
      >
        <div className="flex h-12 w-12 items-center justify-center rounded-full bg-muted">
          {isUploading ? (
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          ) : (
            <UploadCloud className="h-6 w-6 text-muted-foreground" />
          )}
        </div>
        <div className="text-center">
          <p className="text-sm font-medium">
            {projectId ? "اسحب وأفلت الملفات هنا أو اضغط للاختيار" : "اختر مشروعاً أولاً"}
          </p>
          <p className="mt-1 text-xs text-muted-foreground">
            MP4, MOV, WEBM — بحد أقصى 500 ميجابايت
          </p>
        </div>
        <input
          ref={fileInputRef}
          type="file"
          multiple
          accept="video/mp4,video/quicktime,video/webm,.mp4,.mov,.webm"
          className="hidden"
          onChange={handleFileSelect}
        />
      </div>

      {/* Validation Errors */}
      {Object.keys(validationErrors).length > 0 && (
        <div className="space-y-1 rounded-lg border border-destructive/30 bg-destructive/5 p-3">
          {Object.entries(validationErrors).map(([name, error]) => (
            <p key={name} className="text-xs text-destructive">
              <span className="font-medium">{name}:</span> {error}
            </p>
          ))}
        </div>
      )}

      {/* Upload Queue */}
      {hasItems && (
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <h3 className="text-sm font-medium">
              قائمة الرفع ({items.length})
            </h3>
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="sm"
                onClick={clearCompleted}
                disabled={isUploading}
              >
                مسح المكتمل
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={clearAll}
                disabled={isUploading}
              >
                <Trash2 className="h-3.5 w-3.5" />
                مسح الكل
              </Button>
            </div>
          </div>

          <div className="space-y-2">
            {items.map((item) => (
              <UploadProgressItem
                key={item.id}
                item={item}
                onRemove={removeItem}
                onRetry={retryItem}
                onCancel={cancelUpload}
              />
            ))}
          </div>

          {hasPending && (
            <Button
              onClick={startUpload}
              disabled={isUploading || !projectId}
              className="w-full"
            >
              {isUploading ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  جاري الرفع...
                </>
              ) : (
                <>
                  <FolderOpen className="h-4 w-4" />
                  بدء الرفع
                </>
              )}
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { Loader2, X, RotateCcw, CheckCircle2, AlertCircle } from "lucide-react";

import { Button } from "@/components/ui/button";
import { formatBytes } from "@/lib/utils/format";
import { formatDuration } from "@/lib/video/metadata";
import type { UploadQueueItem } from "@/types/video";

/* ============================================
   UploadProgressItem — Single queue item
   Shows status, progress, and actions.
   ============================================ */

type UploadProgressItemProps = {
  item: UploadQueueItem;
  onRemove: (id: string) => void;
  onRetry: (id: string) => void;
  onCancel: (id: string) => void;
};

function StatusIcon({ status }: { status: UploadQueueItem["status"] }) {
  switch (status) {
    case "completed":
      return <CheckCircle2 className="h-4 w-4 text-green-600" />;
    case "failed":
      return <AlertCircle className="h-4 w-4 text-red-500" />;
    case "uploading":
    case "processing":
      return <Loader2 className="h-4 w-4 animate-spin text-blue-500" />;
    default:
      return <div className="h-4 w-4 rounded-full border-2 border-muted-foreground/30" />;
  }
}

const STATUS_LABELS: Record<UploadQueueItem["status"], string> = {
  waiting: "في الانتظار",
  uploading: "جاري الرفع",
  processing: "قيد المعالجة",
  completed: "اكتمل",
  failed: "فشل",
};

export function UploadProgressItem({
  item,
  onRemove,
  onRetry,
  onCancel,
}: UploadProgressItemProps) {
  return (
    <div className="flex items-center gap-3 rounded-lg border p-3">
      <StatusIcon status={item.status} />

      <div className="min-w-0 flex-1">
        <div className="flex items-center justify-between gap-2">
          <p className="truncate text-sm font-medium">{item.file.name}</p>
          <span className="shrink-0 text-xs text-muted-foreground">
            {formatBytes(item.file.size)}
          </span>
        </div>

        <div className="mt-1.5 flex items-center gap-2">
          <div className="h-1.5 flex-1 overflow-hidden rounded-full bg-muted">
            <div
              className="h-full rounded-full bg-primary transition-all duration-300"
              style={{ width: `${item.progress}%` }}
            />
          </div>
          <span className="shrink-0 text-xs text-muted-foreground">
            {STATUS_LABELS[item.status]}
            {item.status === "uploading" && ` ${item.progress}%`}
          </span>
        </div>

        {item.error && (
          <p className="mt-1 text-xs text-destructive">{item.error}</p>
        )}
      </div>

      <div className="flex shrink-0 items-center gap-1">
        {(item.status === "uploading" || item.status === "processing") && (
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            onClick={() => onCancel(item.id)}
            aria-label="إلغاء"
          >
            <X className="h-3.5 w-3.5" />
          </Button>
        )}
        {item.status === "failed" && (
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            onClick={() => onRetry(item.id)}
            aria-label="إعادة"
          >
            <RotateCcw className="h-3.5 w-3.5" />
          </Button>
        )}
        {item.status !== "uploading" && item.status !== "processing" && (
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            onClick={() => onRemove(item.id)}
            aria-label="إزالة"
          >
            <X className="h-3.5 w-3.5" />
          </Button>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useCallback, useEffect, useTransition } from "react";
import {
  Search,
  ArrowUpDown,
  Video,
  Trash2,
  RotateCcw,
  Eye,
  MoreHorizontal,
  ChevronRight,
  ChevronLeft,
} from "lucide-react";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { EmptyState } from "@/components/shared/empty-state";
import { ConfirmDialog } from "@/components/shared/confirm-dialog";
import { VideoStatusBadge } from "@/components/uploads/video-status-badge";
import { VideoPlayer } from "@/components/player/video-player";
import { formatDate } from "@/lib/utils/format";
import { formatBytes } from "@/lib/utils/format";
import { formatDuration, formatResolution } from "@/lib/video/metadata";
import { getUploadsAction } from "@/actions/uploads/get-uploads";
import { deleteUploadAction } from "@/actions/uploads/delete-upload";
import { restoreUploadAction } from "@/actions/uploads/restore-upload";
import { getVideoDetailsAction } from "@/actions/uploads/get-video-details";
import type { VideoTableRow } from "@/types/video";
import type { VideoFilterValue, VideoSortValue } from "@/lib/validations/video";

/* ============================================
   VideoGrid — Video library grid
   Search, filter, sort, pagination
   ============================================ */

const FILTER_OPTIONS: { value: VideoFilterValue; label: string }[] = [
  { value: "ready", label: "جاهز" },
  { value: "processing", label: "قيد المعالجة" },
  { value: "uploading", label: "جاري الرفع" },
  { value: "failed", label: "فشل" },
  { value: "deleted", label: "محذوف" },
];

const SORT_OPTIONS: { value: VideoSortValue; label: string }[] = [
  { value: "newest", label: "الأحدث" },
  { value: "oldest", label: "الأقدم" },
  { value: "duration", label: "المدة" },
  { value: "size", label: "الحجم" },
];

const PAGE_SIZE_OPTIONS = [10, 25, 50, 100];

type VideoGridProps = {
  projectId?: string;
  showProjectColumn?: boolean;
};

export function VideoGrid({ projectId, showProjectColumn = false }: VideoGridProps) {
  const [isPending, startTransition] = useTransition();
  const [data, setData] = useState<{
    items: VideoTableRow[];
    total: number;
    page: number;
    pageSize: number;
    totalPages: number;
  } | null>(null);

  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<VideoFilterValue>("ready");
  const [sort, setSort] = useState<VideoSortValue>("newest");
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(12);

  const [deleteTarget, setDeleteTarget] = useState<VideoTableRow | null>(null);
  const [restoreTarget, setRestoreTarget] = useState<VideoTableRow | null>(null);
  const [playerTarget, setPlayerTarget] = useState<{ url: string; title: string } | null>(null);

  const [searchInput, setSearchInput] = useState("");

  const fetchData = useCallback(async () => {
    startTransition(async () => {
      const result = await getUploadsAction({
        page,
        pageSize,
        projectId,
        search: search || undefined,
        filter,
        sort,
      });
      setData(result);
    });
  }, [page, pageSize, projectId, search, filter, sort]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setSearch(searchInput);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  }, [searchInput]);

  const handleDelete = async () => {
    if (!deleteTarget) return;
    const result = await deleteUploadAction(deleteTarget.id);
    if (result.success) {
      toast.success("تم حذف الفيديو");
      fetchData();
    } else {
      toast.error(result.error ?? "فشل في حذف الفيديو");
    }
    setDeleteTarget(null);
  };

  const handleRestore = async () => {
    if (!restoreTarget) return;
    const result = await restoreUploadAction(restoreTarget.id);
    if (result.success) {
      toast.success("تم استعادة الفيديو");
      fetchData();
    } else {
      toast.error(result.error ?? "فشل في استعادة الفيديو");
    }
    setRestoreTarget(null);
  };

  const handlePlay = async (video: VideoTableRow) => {
    const details = await getVideoDetailsAction(video.id);
    if (details?.signedUrls) {
      setPlayerTarget({
        url: details.signedUrls.streamUrl,
        title: video.title,
      });
    } else {
      toast.error("لا يمكن تشغيل الفيديو");
    }
  };

  const items = data?.items ?? [];
  const total = data?.total ?? 0;
  const totalPages = data?.totalPages ?? 0;
  const isLoading = isPending && !data;

  return (
    <div className="space-y-4">
      {/* Toolbar */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="relative flex-1 max-w-sm">
