  },
  DELETED: {
    label: "محذوف",
    className: "",
  },
};

export function VideoStatusBadge({ status }: { status: string }) {
  const config = STATUS_CONFIG[status];

  if (!config) {
    return <Badge variant="outline">{status}</Badge>;
