  if (!config) {
    return <Badge variant="outline">{status}</Badge>;
  }

  if (status === "DELETED") {
    return <Badge variant="secondary">{config.label}</Badge>;
  }

  return (
    <Badge variant="default" className={config.className}>
      {config.label}
    </Badge>
  );
}
