/* ============================================
   Storage Key Builder
   Generates structured object keys for R2.
   Folder structure:
     projects/
       PR-000001/
         preview.mp4
         final.mp4
         thumbnail.jpg
         assets/
         music/
         invoices/
         contracts/
   ============================================ */

import { randomUUID } from "crypto";

/** Get file extension from filename (lowercase, no dot). */
function ext(filename: string): string {
  const parts = filename.split(".");
  return parts.length > 1 ? parts.pop()!.toLowerCase() : "";
}

/**
 * Build a storage key for a project file.
 * Structure: projects/{projectCode}/{subfolder?}/{uuid}.{ext}
 */
export function buildStorageKey(params: {
  projectCode: string;
  fileName: string;
  subfolder?: "assets" | "music" | "invoices" | "contracts" | null;
}): string {
  const { projectCode, fileName, subfolder } = params;
  const extension = ext(fileName);
  const uuid = randomUUID();

  const parts = ["projects", projectCode];
  if (subfolder) parts.push(subfolder);
  parts.push(`${uuid}${extension ? `.${extension}` : ""}`);

  return parts.join("/");
}

/**
 * Build a storage key for a preview video.
 * Structure: projects/{projectCode}/preview.mp4
 */
export function buildPreviewKey(projectCode: string, extension = "mp4"): string {
  return `projects/${projectCode}/preview.${extension}`;
}

/**
 * Build a storage key for a final video.
 * Structure: projects/{projectCode}/final.mp4
 */
export function buildFinalKey(projectCode: string, extension = "mp4"): string {
  return `projects/${projectCode}/final.${extension}`;
}

/**
 * Build a storage key for a thumbnail.
 * Structure: projects/{projectCode}/thumbnail.jpg
 */
export function buildThumbnailKey(projectCode: string): string {
  return `projects/${projectCode}/thumbnail.jpg`;
}

/**
 * Build a storage key for a video upload (legacy format for compatibility).
 * Structure: videos/{projectId}/{uuid}.{ext}
 */
export function buildVideoKey(projectId: string, fileName: string): string {
  const extension = ext(fileName);
  const uuid = randomUUID();
  return `videos/${projectId}/${uuid}${extension ? `.${extension}` : ""}`;
}

/**
 * Build the prefix for listing all files in a project.
 * Structure: projects/{projectCode}/
 */
export function buildProjectPrefix(projectCode: string): string {
  return `projects/${projectCode}/`;
}

/** Extract the project code from a storage key. */
export function extractProjectCode(key: string): string | null {
  const match = key.match(/^projects\/([A-Z]+-\d+)\//);
  return match?.[1] ?? null;
}

/** Check if a key is a preview video. */
export function isPreviewKey(key: string): boolean {
  return key.includes("/preview.");
}

/** Check if a key is a final video. */
export function isFinalKey(key: string): boolean {
  return key.includes("/final.");
}

import { STORAGE_CONFIG } from "./config";
import { FileValidationError } from "./errors";

/* ============================================
   File Validation Utilities
   Validates file type, MIME, size before upload.
   ============================================ */

/** Supported file type categories. */
export const FILE_TYPE_CATEGORIES = {
  VIDEO: ["mp4", "mov", "webm", "avi"],
  IMAGE: ["jpg", "jpeg", "png", "webp", "gif", "avif"],
  AUDIO: ["mp3", "wav", "aac", "flac", "ogg"],
  DOCUMENT: ["pdf", "doc", "docx", "txt", "rtf"],
  SPREADSHEET: ["xls", "xlsx", "csv"],
  ARCHIVE: ["zip", "rar", "7z", "tar", "gz"],
} as const;

/** MIME type mapping for common extensions. */
const MIME_MAP: Record<string, string> = {
  mp4: "video/mp4",
  mov: "video/quicktime",
  webm: "video/webm",
  avi: "video/x-msvideo",
  jpg: "image/jpeg",
  jpeg: "image/jpeg",
  png: "image/png",
  webp: "image/webp",
  gif: "image/gif",
  avif: "image/avif",
  mp3: "audio/mpeg",
  wav: "audio/wav",
  aac: "audio/aac",
  flac: "audio/flac",
  ogg: "audio/ogg",
  pdf: "application/pdf",
  doc: "application/msword",
  docx: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  txt: "text/plain",
  rtf: "application/rtf",
  xls: "application/vnd.ms-excel",
  xlsx: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
  csv: "text/csv",
  zip: "application/zip",
  rar: "application/vnd.rar",
  "7z": "application/x-7z-compressed",
};

export type ValidationResult = {
  valid: boolean;
  error?: string;
  mimeType?: string;
  extension?: string;
};

/** Get extension from filename (lowercase, no dot). */
export function getExtension(filename: string): string {
  const parts = filename.split(".");
  return parts.length > 1 ? parts.pop()!.toLowerCase() : "";
}

/** Get MIME type from extension. */
export function getMimeType(filename: string): string {
  const ext = getExtension(filename);
  return MIME_MAP[ext] ?? "application/octet-stream";
}

/**
 * Validate a video file against upload limits.
 * Checks: extension, MIME type, file size, empty file.
 */
export function validateVideoFile(file: { name: string; size: number; type?: string }): ValidationResult {
  const ext = getExtension(file.name);
  const mimeType = file.type || getMimeType(file.name);

  if (!ext) {
    return { valid: false, error: "الملف لا يحتوي على امتداد", extension: ext };
  }

  const allowedFormats = STORAGE_CONFIG.LIMITS.ALLOWED_VIDEO_FORMATS as readonly string[];
  if (!allowedFormats.includes(ext)) {
    return {
      valid: false,
      error: `صيغة غير مدعومة. الصيغ المسموحة: ${allowedFormats.join(", ")}`,
      extension: ext,
      mimeType,
    };
  }

  if (file.size <= 0) {
    return { valid: false, error: "الملف فارغ", extension: ext, mimeType };
  }

  const maxSize = STORAGE_CONFIG.LIMITS.MAX_FILE_SIZE;
  if (file.size > maxSize) {
    const maxSizeMB = Math.round(maxSize / (1024 * 1024));
    return {
      valid: false,
      error: `حجم الملف يتجاوز الحد الأقصى (${maxSizeMB} ميجابايت)`,
      extension: ext,
      mimeType,
    };
  }

  return { valid: true, extension: ext, mimeType };
}

/**
 * Validate any file against allowed categories.
 */
export function validateFile(
  file: { name: string; size: number; type?: string },
  allowedCategories: (keyof typeof FILE_TYPE_CATEGORIES)[] = ["VIDEO", "IMAGE", "DOCUMENT"],
  maxSize?: number,
): ValidationResult {
  const ext = getExtension(file.name);
  const mimeType = file.type || getMimeType(file.name);

  if (!ext) {
    return { valid: false, error: "الملف لا يحتوي على امتداد" };
  }

  const allowedExtensions = allowedCategories.flatMap(
    (cat) => FILE_TYPE_CATEGORIES[cat] as readonly string[],
  );

  if (!allowedExtensions.includes(ext)) {
    return {
      valid: false,
      error: `نوع الملف غير مدعوم. الأنواع المسموحة: ${allowedExtensions.join(", ")}`,
      extension: ext,
      mimeType,
    };
  }

  if (file.size <= 0) {
    return { valid: false, error: "الملف فارغ", extension: ext, mimeType };
  }

  const limit = maxSize ?? STORAGE_CONFIG.LIMITS.MAX_FILE_SIZE;
  if (file.size > limit) {
    const limitMB = Math.round(limit / (1024 * 1024));
    return {
      valid: false,
      error: `حجم الملف يتجاوز الحد الأقصى (${limitMB} ميجابايت)`,
      extension: ext,
      mimeType,
    };
  }

  return { valid: true, extension: ext, mimeType };
}

/**
 * Throw a FileValidationError if validation fails.
 */
export function assertValid(
  file: { name: string; size: number; type?: string },
  allowedCategories: (keyof typeof FILE_TYPE_CATEGORIES)[] = ["VIDEO", "IMAGE", "DOCUMENT"],
  maxSize?: number,
): void {
  const result = validateFile(file, allowedCategories, maxSize);
  if (!result.valid) {
    throw new FileValidationError(result.error ?? "فشل في التحقق من الملف");
  }
}

import type {
  UploadParams,
  SignedUrlOptions,
  FileMetadata,
  ListFilesOptions,
  ListFilesResult,
  CopyFileOptions,
} from "./types";

/* ============================================
   StorageProvider Interface
   Provider-agnostic contract for file storage.
   Every provider (R2, S3, etc.) must implement
   this interface. No provider-specific types
   leak here.
   ============================================ */

export interface StorageProvider {
  /** Human-readable provider name. */
  readonly name: string;

  /** The bucket/container name. */
  readonly bucket: string;

  /**
   * Upload a file to storage.
   * @returns the object key on success.
   */
  upload(params: UploadParams): Promise<string>;

  /**
   * Replace a file — deletes the old key, uploads the new one.
   * @returns the new object key.
   */
  replace(oldKey: string, params: UploadParams): Promise<string>;

  /**
   * Delete a single object from storage.
   */
  delete(key: string): Promise<void>;

  /**
   * Move/rename an object within the same bucket.
   * @returns the new object key.
   */
  moveFile(sourceKey: string, destinationKey: string): Promise<string>;

  /**
   * Copy an object within the same bucket.
   * @returns the new object key.
   */
  copyFile(sourceKey: string, destinationKey: string, options?: CopyFileOptions): Promise<string>;

  /**
   * List objects in the bucket with an optional prefix.
   */
  listFiles(options?: ListFilesOptions): Promise<ListFilesResult>;

  /**
   * Check if an object exists in storage.
   */
  exists(key: string): Promise<boolean>;

  /**
   * Get object metadata (size, content-type, etag, etc.).
   */
  getMetadata(key: string): Promise<FileMetadata>;

  /**
   * Generate a signed URL for downloading a private object.
   */
  getSignedUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a signed download URL.
   * Uses download-specific expiration by default.
   * Sets Content-Disposition to attachment.
   */
  getDownloadUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a signed streaming URL.
   * Uses streaming-specific expiration by default.
   * Supports range requests for video seeking.
   */
  getStreamingUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a presigned URL for direct browser upload.
   * @returns a temporary upload URL.
   */
  generateUploadUrl(
    key: string,
    contentType: string,
    options?: SignedUrlOptions
  ): Promise<string>;
}

/* ============================================
   Storage Types
   Provider-agnostic types shared across
   the storage abstraction layer.
   ============================================ */

/** Parameters for uploading a file to storage. */
export type UploadParams = {
  key: string;
  body: Buffer | Uint8Array;
  contentType: string;
  metadata?: Record<string, string>;
};

/** Options for signed URL generation. */
export type SignedUrlOptions = {
  /** Expiration in seconds. */
  expiresIn?: number;

  /** Content-Disposition header for downloads. */
  responseContentDisposition?: string;
};

/** Result of a signed URL generation. */
export type SignedUrlResult = {
  url: string;
  expiresAt: number;
};

/** Object metadata returned by getMetadata(). */
export type FileMetadata = {
  key: string;
  size: number;
  contentType: string | null;
  lastModified: Date | null;
  etag: string | null;
  metadata: Record<string, string>;
};

/** Options for listFiles(). */
export type ListFilesOptions = {
  /** Prefix to filter objects by. */
  prefix?: string;
  /** Maximum number of objects to return (default: 1000). */
  maxKeys?: number;
  /** Continuation token from a previous request. */
  continuationToken?: string;
};

/** Result of listFiles(). */
export type ListFilesResult = {
  items: Array<{
    key: string;
    size: number;
    lastModified: Date;
    etag: string | null;
  }>;
  isTruncated: boolean;
  continuationToken: string | null;
};

/** Options for copyFile(). */
export type CopyFileOptions = {
  /** Overwrite if destination already exists (default: true). */
  overwrite?: boolean;
};

/** Configuration for a storage provider. */
export type StorageProviderConfig = {
  bucket: string;
  endpoint?: string;
  accessKey?: string;
  secretKey?: string;
  accountId?: string;
};

/** Supported storage provider names. */
export type StorageProviderName = "cloudflare-r2" | "aws-s3";

